sql:
SELECT guide_id, update_date, update_description
FROM guide_history
ORDER BY guide_id ASC, update_date ASC;

SELECT experiment_conditions, AVG(on_target_efficacy) AS average_efficacy
FROM guide_performance
GROUP BY experiment_conditions;

SELECT target_genome_gene_locus, AVG(offtarget_count) AS average_offtarget_count
FROM guides
GROUP BY target_genome_gene_locus;

SELECT seq_id, target_seq
FROM guides
WHERE doench_score > 0.5;

SELECT seq_id, target_seq, mit_spec_score
FROM guides
ORDER BY mit_spec_score DESC;

SELECT guide_id
FROM guides
WHERE doench_score > (SELECT AVG(doench_score) FROM guides);

SELECT guide_id, seq_id, target_seq, doench_score, moreno_mateos_score
FROM guides
ORDER BY doench_score DESC;

SELECT user_id, COUNT(comment_id) AS num_comments
FROM guide_comments
GROUP BY user_id;

SELECT users.user_name, users.email, users.role, users.institution, guide_designs.design_date, guide_designs.design_parameters, guide_designs.design_notes
FROM users
INNER JOIN guide_designs ON users.user_id = guide_designs.user_id;

SELECT DISTINCT u.user_name
FROM users u
JOIN guide_comments gc ON u.user_id = gc.user_id;
